// ❌ BAD — data is public, anyone can corrupt it
class BankAccount {
    public double balance = 1000.0;  // anyone can do account.balance = -9999
}

BankAccount acc = new BankAccount();
acc.balance = -9999;   // 💥 corrupted! No rule was enforced

// ✅ GOOD — data is private, only controlled access via methods
class BankAccount {
    private double balance;       // hidden — the outside world can't touch it
    private String owner;
    private List<String> transactionLog = new ArrayList<>();

    public BankAccount(String owner, double initialBalance) {
        if (initialBalance < 0) throw new IllegalArgumentException("Balance can't be negative");
        this.owner = owner;
        this.balance = initialBalance;
    }

    // Controlled READ — getter
    public double getBalance() { return balance; }

    // Controlled WRITE — business rules enforced
    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Deposit must be positive");
        balance += amount;
        transactionLog.add("DEPOSIT: +" + amount);
    }

    public void withdraw(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Must be positive");
        if (amount > balance) throw new IllegalStateException("Insufficient funds");
        balance -= amount;
        transactionLog.add("WITHDRAW: -" + amount);
    }

    // Internal implementation can change — the API stays the same
    public List<String> getHistory() {
        return Collections.unmodifiableList(transactionLog);  // defensive copy
    }
}

// Usage
BankAccount acc = new BankAccount("Alice", 1000.0);
acc.deposit(500);
acc.withdraw(200);
System.out.println(acc.getBalance());    // 1300.0
// acc.balance = -9999;  ← compile error — balance is private

// Abstraction = define WHAT an object can do, not HOW it does it
// Achieved via abstract classes and interfaces

// The "what" — a contract
public interface PaymentGateway {
    PaymentResult charge(String customerId, double amount);
    RefundResult refund(String transactionId);
    boolean isAvailable();
}

// The "how" — multiple implementations, all hidden from the caller
public class StripeGateway implements PaymentGateway {
    private final StripeClient stripeClient;

    @Override
    public PaymentResult charge(String customerId, double amount) {
        // Stripe-specific logic — HTTP calls, retries, auth
        // Caller knows NOTHING about this
        StripeCharge charge = stripeClient.charges().create(customerId, amount);
        return new PaymentResult(charge.getId(), charge.getStatus());
    }
    // ...
}

public class PayPalGateway implements PaymentGateway {
    @Override
    public PaymentResult charge(String customerId, double amount) {
        // PayPal-specific logic — completely different internally
        // But same external interface
    }
    // ...
}

// The caller uses the abstraction — doesn't care which gateway
public class OrderService {
    private final PaymentGateway gateway;   // ← type is the interface

    public void processOrder(Order order) {
        PaymentResult result = gateway.charge(order.getCustomerId(), order.getTotal());
        if (result.isSuccess()) {
            order.markPaid();
        }
    }
}
// Swap Stripe for PayPal → OrderService needs ZERO changes

// Inheritance = a child class gets all the parent's fields and methods
// Child IS-A parent (User IS-A Person)

public class Person {
    protected String name;
    protected String email;

    public Person(String name, String email) {
        this.name = name;
        this.email = email;
    }

    public String greet() {
        return "Hi, I'm " + name;
    }
}

public class User extends Person {
    private String username;
    private String passwordHash;

    public User(String name, String email, String username) {
        super(name, email);    // call parent constructor
        this.username = username;
    }

    @Override
    public String greet() {
        return super.greet() + " (username: " + username + ")";
    }

    public boolean login(String password) {
        return hashPassword(password).equals(passwordHash);
    }
}

public class AdminUser extends User {
    private List<String> permissions;

    public AdminUser(String name, String email, String username) {
        super(name, email, username);
        this.permissions = new ArrayList<>();
    }

    public void grantPermission(String permission) {
        permissions.add(permission);
    }

    public boolean hasPermission(String permission) {
        return permissions.contains(permission);
    }
}

// ⚠️ KEY RULE: only use inheritance for TRUE IS-A relationships
// "AdminUser IS-A User" ✅
// "Car IS-A Engine" ❌ (Car HAS-A Engine → use composition)

// Polymorphism = same method name, different behaviour per object type
// The most powerful OOP pillar for writing flexible code

public abstract class Shape {
    public abstract double area();      // every shape MUST implement this
    public abstract double perimeter();

    public void describe() {
        System.out.printf("Shape: area=%.2f, perimeter=%.2f%n", area(), perimeter());
    }
}

public class Circle extends Shape {
    private double radius;
    public Circle(double radius) { this.radius = radius; }

    @Override
    public double area() { return Math.PI * radius * radius; }

    @Override
    public double perimeter() { return 2 * Math.PI * radius; }
}

public class Rectangle extends Shape {
    private double width, height;
    public Rectangle(double w, double h) { width = w; height = h; }

    @Override
    public double area() { return width * height; }

    @Override
    public double perimeter() { return 2 * (width + height); }
}

// The magic — process ALL shapes with one loop, no type checking
List<Shape> shapes = List.of(
    new Circle(5),
    new Rectangle(4, 6),
    new Circle(3),
    new Rectangle(10, 2)
);

for (Shape shape : shapes) {
    shape.describe();    // each calls ITS OWN area() and perimeter()
}

double totalArea = shapes.stream()
    .mapToDouble(Shape::area)
    .sum();

// ❌ Without polymorphism — fragile, must update for every new shape:
if (shape instanceof Circle) { ... }
else if (shape instanceof Rectangle) { ... }
