// ❌ BAD — UserService does EVERYTHING
// If email format changes → edit this class
// If DB schema changes → edit this class
// If password rules change → edit this class
// If logging format changes → edit this class
// 4 different reasons to change = 4 responsibilities = violation

public class UserService {
    public void registerUser(String email, String password) {
        // Responsibility 1: Validation
        if (!email.contains("@")) throw new RuntimeException("Invalid email");
        if (password.length() < 8) throw new RuntimeException("Password too short");

        // Responsibility 2: Password hashing
        String hash = BCrypt.hashpw(password, BCrypt.gensalt());

        // Responsibility 3: Database persistence
        String sql = "INSERT INTO users (email, password) VALUES (?, ?)";
        jdbcTemplate.update(sql, email, hash);

        // Responsibility 4: Email sending
        String body = "Welcome to our app!";
        JavaMailSender.send(email, "Welcome", body);

        // Responsibility 5: Logging
        System.out.println("[" + LocalDateTime.now() + "] User registered: " + email);
    }
}

// ✅ GOOD — each class has ONE reason to change

// Responsibility 1: Validation rules only
public class UserValidator {
    public void validate(String email, String password) {
        if (email == null || !email.matches("^[^@]+@[^@]+\.[^@]+$"))
            throw new IllegalArgumentException("Invalid email format");
        if (password == null || password.length() < 8)
            throw new IllegalArgumentException("Password must be 8+ characters");
    }
}

// Responsibility 2: Password security only
public class PasswordService {
    public String hash(String plaintext) {
        return BCrypt.hashpw(plaintext, BCrypt.gensalt(12));
    }
    public boolean verify(String plaintext, String hashed) {
        return BCrypt.checkpw(plaintext, hashed);
    }
}

// Responsibility 3: Database access only
@Repository
public class UserRepository {
    public User save(User user) { return jpaRepository.save(user); }
    public Optional<User> findByEmail(String email) { return jpaRepository.findByEmail(email); }
}

// Responsibility 4: Email communication only
@Service
public class EmailService {
    public void sendWelcomeEmail(String email, String name) {
        // constructs and sends the email
    }
    public void sendPasswordResetEmail(String email, String token) { ... }
}

// Orchestrator — thin layer that coordinates the others
@Service
public class UserRegistrationService {
    private final UserValidator validator;
    private final PasswordService passwordService;
    private final UserRepository userRepository;
    private final EmailService emailService;

    public User registerUser(RegisterRequest req) {
        validator.validate(req.getEmail(), req.getPassword());
        String hash = passwordService.hash(req.getPassword());
        User user = userRepository.save(new User(req.getEmail(), hash));
        emailService.sendWelcomeEmail(user.getEmail(), user.getName());
        return user;
    }
}

// Now each class changes for ONE reason only:
// Email format changes?   → edit UserValidator only
// BCrypt cost changes?    → edit PasswordService only
// DB schema changes?      → edit UserRepository only
// Welcome text changes?   → edit EmailService only

// ❌ Fat controller — doing too much
@RestController
public class ProductController {
    @GetMapping("/products/{id}")
    public ResponseEntity<?> getProduct(@PathVariable Long id) {
        // Querying DB directly in controller — wrong layer
        Product p = jdbcTemplate.queryForObject("SELECT * FROM products WHERE id=?", id);
        // Business logic in controller — wrong place
        if (p.getStock() < 0) p.setStock(0);
        // DTO conversion in controller — wrong place
        ProductDTO dto = new ProductDTO(p.getId(), p.getName(), p.getPrice());
        return ResponseEntity.ok(dto);
    }
}

// ✅ Thin controller — only HTTP concern
@RestController
@RequestMapping("/products")
public class ProductController {
    private final ProductService productService;  // delegates ALL logic

    @GetMapping("/{id}")
    public ResponseEntity<ProductDTO> getProduct(@PathVariable Long id) {
        return productService.findById(id)
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
        // Controller's ONLY job: HTTP in → call service → HTTP out
    }
}

// Controller = HTTP routing + request/response mapping
// Service    = business logic + orchestration
// Repository = data access
// Each has ONE reason to change

// ❌ BAD — add new shape type → MUST edit this existing code
// Violates OCP — it's open for modification, not extension
public class AreaCalculator {
    public double calculate(Object shape) {
        if (shape instanceof Circle) {
            Circle c = (Circle) shape;
            return Math.PI * c.getRadius() * c.getRadius();
        } else if (shape instanceof Rectangle) {
            Rectangle r = (Rectangle) shape;
            return r.getWidth() * r.getHeight();
        } else if (shape instanceof Triangle) {   // ← added later, touched existing code
            Triangle t = (Triangle) shape;
            return 0.5 * t.getBase() * t.getHeight();
        }
        // Add Pentagon? Edit this method again. And again. And again.
        throw new UnsupportedOperationException("Unknown shape");
    }
}

// ✅ GOOD — add new shape → zero changes to existing code
// Each shape knows how to calculate its own area
public interface Shape {
    double area();   // the contract — every shape MUST implement this
}

public class Circle implements Shape {
    private double radius;
    @Override
    public double area() { return Math.PI * radius * radius; }
}

public class Rectangle implements Shape {
    private double width, height;
    @Override
    public double area() { return width * height; }
}

// AreaCalculator is now CLOSED — never needs to change
public class AreaCalculator {
    public double calculate(Shape shape) {
        return shape.area();   // polymorphism handles dispatch
    }

    public double calculateTotal(List<Shape> shapes) {
        return shapes.stream().mapToDouble(Shape::area).sum();
    }
}

