// Problem: Support multiple discount types without editing order processing logic

// ✅ Step 1: Define the abstraction (the "closed" interface)
public interface DiscountStrategy {
    double apply(double originalPrice);
    String describe();
}

// ✅ Step 2: Implement each discount independently
public class NoDiscount implements DiscountStrategy {
    @Override
    public double apply(double price) { return price; }
    @Override
    public String describe() { return "No discount applied"; }
}

public class PercentageDiscount implements DiscountStrategy {
    private final double percentage;
    public PercentageDiscount(double percentage) { this.percentage = percentage; }

    @Override
    public double apply(double price) { return price * (1 - percentage / 100); }
    @Override
    public String describe() { return percentage + "% discount applied"; }
}

public class FlatDiscount implements DiscountStrategy {
    private final double amount;
    public FlatDiscount(double amount) { this.amount = amount; }

    @Override
    public double apply(double price) { return Math.max(0, price - amount); }
    @Override
    public String describe() { return "Flat $" + amount + " off"; }
}

public class BuyOneGetOneDiscount implements DiscountStrategy {
    @Override
    public double apply(double price) { return price / 2; }    // half price
    @Override
    public String describe() { return "Buy one get one — 50% off"; }
}

// ✅ Step 3: OrderService is CLOSED — never changes when discounts are added
@Service
public class OrderService {
    public Order checkout(Cart cart, DiscountStrategy discount) {
        double originalTotal = cart.getTotal();
        double discountedTotal = discount.apply(originalTotal);
        return new Order(cart, discountedTotal, discount.describe());
    }
}

// New seasonal discount? Just add a new class — OrderService untouched
public class SeasonalDiscount implements DiscountStrategy {
    @Override
    public double apply(double price) { return price * 0.75; }  // 25% off
    @Override
    public String describe() { return "Seasonal sale: 25% off"; }
}

// Add new notification channels without touching the notification engine

// The closed interface
public interface NotificationChannel {
    void send(Notification notification);
    boolean supports(String channelType);
}

// Each channel is a separate, independent class
@Component
public class EmailNotification implements NotificationChannel {
    private final JavaMailSender mailSender;

    @Override
    public void send(Notification n) {
        SimpleMailMessage msg = new SimpleMailMessage();
        msg.setTo(n.getRecipient());
        msg.setSubject(n.getTitle());
        msg.setText(n.getBody());
        mailSender.send(msg);
    }

    @Override
    public boolean supports(String channelType) { return "EMAIL".equals(channelType); }
}

@Component
public class SmsNotification implements NotificationChannel {
    private final TwilioClient twilioClient;

    @Override
    public void send(Notification n) {
        twilioClient.messages().create(n.getPhone(), n.getBody());
    }

    @Override
    public boolean supports(String channelType) { return "SMS".equals(channelType); }
}

@Component
public class PushNotification implements NotificationChannel {
    @Override
    public void send(Notification n) { /* FCM push logic */ }
    @Override
    public boolean supports(String channelType) { return "PUSH".equals(channelType); }
}

// NotificationService is PERMANENTLY CLOSED — never changes
@Service
public class NotificationService {
    // Spring auto-injects ALL beans implementing NotificationChannel
    private final List<NotificationChannel> channels;

    public void send(Notification notification) {
        channels.stream()
            .filter(c -> c.supports(notification.getChannelType()))
            .findFirst()
            .orElseThrow(() -> new UnsupportedOperationException(
                "No handler for: " + notification.getChannelType()))
            .send(notification);
    }
}

