// NotificationService: not a single character changes ✅

// ❌ BAD — Classic LSP violation
public class Rectangle {
    protected int width;
    protected int height;

    public void setWidth(int w)  { this.width = w; }
    public void setHeight(int h) { this.height = h; }
    public int area() { return width * height; }
}

public class Square extends Rectangle {
    // Square MUST keep width == height always
    @Override
    public void setWidth(int w)  { this.width = w; this.height = w; }  // ← surprise!
    @Override
    public void setHeight(int h) { this.width = h; this.height = h; }  // ← surprise!
}

// Code written for Rectangle — breaks silently with Square
public void resize(Rectangle rect) {
    rect.setWidth(5);
    rect.setHeight(10);
    // Any Rectangle: area = 50 ✅
    // A Square: area = 100 ❌ — Square overrode setHeight to also change width!
    assert rect.area() == 50;   // FAILS for Square
}

resize(new Rectangle());   // passes ✅
resize(new Square());      // fails ❌  — LSP violated

// ✅ FIX — don't use inheritance; use a common interface instead
public interface Shape { int area(); }

public class Rectangle implements Shape {
    private final int width, height;
    public Rectangle(int w, int h) { this.width = w; this.height = h; }
    @Override
    public int area() { return width * height; }
}

public class Square implements Shape {
    private final int side;
    public Square(int side) { this.side = side; }
    @Override
    public int area() { return side * side; }
}
// Now no surprises — they share the interface, not a broken hierarchy

