// Code using UserRepository ASSUMES save works. LSP violated.
public class UserService {
    private final UserRepository repo;  // ← could secretly be ReadOnly
    public void createUser(User u) {
        repo.save(u);   // 💥 UnsupportedOperationException at runtime!
    }
}

// ✅ FIX — segregate the interfaces properly
public interface ReadableUserRepository {
    Optional<User> findById(Long id);
    List<User> findAll();
}

public interface WritableUserRepository extends ReadableUserRepository {
    User save(User user);
    void delete(Long id);
}

// ReadOnly only implements what it CAN do — no broken promises
public class ReadOnlyUserRepository implements ReadableUserRepository {
    @Override
    public Optional<User> findById(Long id) { return database.findById(id); }
    @Override
    public List<User> findAll() { return database.findAll(); }
}

// Services request ONLY what they need
public class UserQueryService {
    private final ReadableUserRepository repo;  // ← won't even try to save
}
public class UserCommandService {
    private final WritableUserRepository repo;  // ← can save and delete
}

// LSP has formal rules about what subclasses can and cannot do:
//
// PRECONDITIONS (what the method requires from caller):
//   Subclass can WEAKEN (require less) — never STRENGTHEN (require more)
//
// POSTCONDITIONS (what the method promises to the caller):
//   Subclass can STRENGTHEN (guarantee more) — never WEAKEN (promise less)

public class EmailService {
    // Precondition: email must not be null
    // Postcondition: email is sent, returns the message ID
    public String sendEmail(String email, String subject, String body) {
        Objects.requireNonNull(email, "email required");
        // send...
        return generateMessageId();
    }
}

// ✅ GOOD subclass — weakens precondition (accepts more), strengthens postcondition
public class ResilientEmailService extends EmailService {
    @Override
    public String sendEmail(String email, String subject, String body) {
        // Accepts null email now — weakened precondition ✅
        if (email == null) email = "fallback@example.com";
        String id = super.sendEmail(email, subject, body);
        // Also logs and retries — strengthened postcondition ✅
        auditLog.record(id, email);
        return id;
    }
}

// ❌ BAD subclass — strengthens precondition (accepts less), breaks callers
public class StrictEmailService extends EmailService {
    @Override
    public String sendEmail(String email, String subject, String body) {
        // Requires email to be @company.com — STRONGER precondition ❌
        if (!email.endsWith("@company.com"))
            throw new IllegalArgumentException("Only company emails!");
        return super.sendEmail(email, subject, body);
    }
}
// Code that worked with EmailService now breaks with StrictEmailService
// That's an LSP violation

// ❌ BAD — one fat interface for all workers
public interface Worker {
    void work();
    void eat();
    void sleep();
    void attendMeeting();
    void submitExpenseReport();
}

// RobotWorker can WORK but cannot eat, sleep, or submit expense reports
// Forced to implement methods that make no sense
public class RobotWorker implements Worker {
    @Override
    public void work() { System.out.println("Robot working..."); }

    @Override
    public void eat() {
        throw new UnsupportedOperationException("Robots don't eat!");   // ❌ violation
    }
    @Override
    public void sleep() {
        throw new UnsupportedOperationException("Robots don't sleep!"); // ❌ violation
    }
    @Override
    public void attendMeeting() { /* forced stub — does nothing */ }    // ❌ meaningless
    @Override
    public void submitExpenseReport() { /* forced stub */ }             // ❌ meaningless
}

// ✅ GOOD — split into focused interfaces
public interface Workable      { void work(); }
public interface Eatable       { void eat(); }
public interface Sleepable     { void sleep(); }
public interface MeetingGoer   { void attendMeeting(); }
public interface ExpenseSubmitter { void submitExpenseReport(); }

// Human implements everything it can actually do
public class HumanWorker implements Workable, Eatable, Sleepable, MeetingGoer, ExpenseSubmitter {
    @Override public void work()                { System.out.println("Human working"); }
    @Override public void eat()                 { System.out.println("Eating lunch"); }
    @Override public void sleep()               { System.out.println("Sleeping"); }
    @Override public void attendMeeting()       { System.out.println("In meeting"); }
    @Override public void submitExpenseReport() { System.out.println("Submitting expenses"); }
}

// Robot only implements what it can do — no forced stubs, no exceptions
public class RobotWorker implements Workable {
    @Override public void work() { System.out.println("Robot working 24/7"); }
}

// Spring's JpaRepository has 20+ methods — often you need only a few
// Services should depend on narrow interfaces

// ❌ BAD — service depends on EVERYTHING in the repository
@Service
public class UserQueryService {
    private final UserRepository repo;   // JpaRepository<User, Long> — 20+ methods

    // This service only READS — but it can now accidentally call repo.delete()
    // or repo.deleteAll() or repo.saveAll() — no guard at all
    public UserDTO getUser(Long id) {
        return repo.findById(id).map(mapper::toDTO).orElseThrow();
    }
}

// ✅ GOOD — define narrow interfaces for what each service actually needs
// Read-only interface — query side
public interface UserReadRepository {
    Optional<User> findById(Long id);
    List<User> findByRole(String role);
    List<User> findAllActive();
    long countByRole(String role);
}

// Write interface — command side
public interface UserWriteRepository {
    User save(User user);
    void deleteById(Long id);
}

// The actual Spring Data repo implements BOTH
@Repository
public interface UserRepository
    extends JpaRepository<User, Long>, UserReadRepository, UserWriteRepository {
    // Spring generates all implementations
}

// Query service: depends ONLY on reading interface
@Service
public class UserQueryService {
    private final UserReadRepository repo;   // ← cannot accidentally delete!
    public UserDTO getUser(Long id) {
        return repo.findById(id).map(mapper::toDTO).orElseThrow();
    }
}

// Command service: depends on write interface
@Service
public class UserCommandService {
    private final UserWriteRepository repo;
    public User createUser(CreateUserRequest req) {
        return repo.save(new User(req.getEmail(), hashPassword(req.getPassword())));
    }
}

// Each use case has its own tiny interface — maximum flexibility

