// Controllers depend ONLY on the interfaces they actually use
// AdminController can delete — regular UserController cannot
@RestController
@RequestMapping("/admin/users")
public class AdminUserController {
    private final GetUserUseCase getUser;
    private final DeleteUserUseCase deleteUser;   // only admin can delete

