@RestController
@RequestMapping("/users")
public class UserController {
    private final GetUserUseCase getUser;
    private final UpdateUserUseCase updateUser;   // users can update self, not delete

    @GetMapping("/{id}")
    public UserDTO get(@PathVariable Long id) { return getUser.getUser(id); }
}

// ❌ BAD — OrderService creates its own dependencies
// High-level module depends directly on low-level module
public class OrderService {
    // 💥 Hardcoded — tightly coupled to MySQL and Gmail
    private MySQLOrderRepository orderRepo = new MySQLOrderRepository();
    private GmailNotifier emailNotifier    = new GmailNotifier("smtp.gmail.com", 587);
    private StripePaymentGateway stripe    = new StripePaymentGateway("sk_live_...");

    public Order createOrder(OrderRequest req) {
        Order order = orderRepo.save(new Order(req));   // must run MySQL
        stripe.charge(order.getCustomer(), order.getTotal());   // must have Stripe key
        emailNotifier.send(order.getEmail(), "Order confirmed");   // must have Gmail
        return order;
    }
}

// Problems:
// 1. To test OrderService you MUST have MySQL, Stripe, and Gmail configured
// 2. Switch from MySQL to PostgreSQL → edit OrderService
// 3. Switch from Stripe to PayPal → edit OrderService
// 4. No way to test with fake/mock dependencies

// ✅ GOOD — depend on interfaces, receive dependencies via constructor
public class OrderService {
    private final OrderRepository orderRepo;       // ← interface, not MySQL
    private final PaymentGateway paymentGateway;   // ← interface, not Stripe
    private final Notifier notifier;               // ← interface, not Gmail

    // Dependencies INJECTED from outside — not created inside
    public OrderService(OrderRepository orderRepo,
                        PaymentGateway paymentGateway,
                        Notifier notifier) {
