// 3 behaviours × 8 combinations = 8 classes, and growing

// ✅ GOOD — compose the behaviours you want
@FunctionalInterface interface Walkable  { void walk(); }
@FunctionalInterface interface Swimmable { void swim(); }
@FunctionalInterface interface Flyable   { void fly(); }
@FunctionalInterface interface Quackable { String quack(); }

public class Animal {
    private final String name;
    private final Walkable walkBehaviour;
    private final Swimmable swimBehaviour;
    private final Flyable flyBehaviour;
    private final Quackable quackBehaviour;

    public Animal(String name, Walkable walk, Swimmable swim,
                  Flyable fly, Quackable quack) {
        this.name = name;
        this.walkBehaviour = walk;
        this.swimBehaviour = swim;
        this.flyBehaviour  = fly;
        this.quackBehaviour = quack;
    }

    public void performWalk()  { if (walkBehaviour != null) walkBehaviour.walk(); }
    public void performSwim()  { if (swimBehaviour != null) swimBehaviour.swim(); }
    public void performFly()   { if (flyBehaviour != null) flyBehaviour.fly(); }
    public String performQuack() { return quackBehaviour != null ? quackBehaviour.quack() : "..."; }
}

