// Decorator = wrap an object in another object that adds behaviour
// Each layer adds something, the core stays unchanged

// Base interface
public interface TextTransformer {
    String transform(String text);
}

// Core implementation
public class PlainText implements TextTransformer {
    @Override
    public String transform(String text) { return text; }
}

// Decorators — each wraps another TextTransformer
public class UpperCaseDecorator implements TextTransformer {
    private final TextTransformer inner;
    public UpperCaseDecorator(TextTransformer inner) { this.inner = inner; }

    @Override
    public String transform(String text) {
        return inner.transform(text).toUpperCase();
    }
}

public class TrimDecorator implements TextTransformer {
    private final TextTransformer inner;
    public TrimDecorator(TextTransformer inner) { this.inner = inner; }

    @Override
    public String transform(String text) {
        return inner.transform(text.trim());
    }
}

public class ExclamationDecorator implements TextTransformer {
    private final TextTransformer inner;
    public ExclamationDecorator(TextTransformer inner) { this.inner = inner; }

    @Override
    public String transform(String text) {
        return inner.transform(text) + "!!!";
    }
}

// Compose at runtime — infinite combinations, no new classes
TextTransformer simple   = new PlainText();
TextTransformer trimOnly = new TrimDecorator(new PlainText());
TextTransformer allThree = new ExclamationDecorator(
                              new UpperCaseDecorator(
                                  new TrimDecorator(new PlainText())));

simple.transform("  hello  ");    // "  hello  "
trimOnly.transform("  hello  ");  // "hello"
allThree.transform("  hello  ");  // "HELLO!!!"

