// ✅ UserService COMPOSED from parts — thin orchestrator
@Service
public class UserService {
    private final UserValidator validator;       // HAS-A
    private final PasswordHasher hasher;         // HAS-A
    private final AuditLogger auditLogger;       // HAS-A
    private final WelcomeEmailSender emailSender; // HAS-A
    private final UserRepository repository;     // HAS-A

    public User register(RegisterRequest req) {
        validator.validateRegistration(req.getEmail(), req.getPassword());
        String hash = hasher.hash(req.getPassword());
        User user = repository.save(new User(req.getEmail(), hash));
        emailSender.send(user);
        auditLogger.logUserCreated(user.getEmail());
        return user;
    }
}

