// Inheritance is right when ALL of these are true:
//   ✅ TRUE IS-A relationship (not just "looks similar")
//   ✅ Shallow hierarchy (1-2 levels max)
//   ✅ Subclass never overrides to throw an exception or do nothing
//   ✅ Subclass never needs a different base implementation

// ✅ GOOD use of inheritance — Spring abstractions
public abstract class BaseEntity {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @CreatedDate
    private LocalDateTime createdAt;

    @LastModifiedDate
    private LocalDateTime updatedAt;

    // All entities ARE BaseEntities — true IS-A
}

@Entity public class User extends BaseEntity    { private String email; ... }
@Entity public class Product extends BaseEntity { private String name; ... }
@Entity public class Order extends BaseEntity   { private String status; ... }
// Hierarchy is 1 level. Subclasses add fields. They never override to break things.

// ✅ GOOD — template method pattern
public abstract class ReportGenerator {
    // Template method — defines the algorithm skeleton
    public final Report generate(ReportRequest req) {
        List<Object> data = fetchData(req);         // step 1
        List<Object> filtered = filterData(data);   // step 2
        return formatReport(filtered);              // step 3
    }
    // Subclasses customise individual steps
    protected abstract List<Object> fetchData(ReportRequest req);
    protected abstract List<Object> filterData(List<Object> data);
    protected abstract Report formatReport(List<Object> data);
}

